(function() {
"use strict";

var currentLesson = null;
var currentTab = "reading";
var completedLessons = JSON.parse(localStorage.getItem("feCompleted") || "[]");
var vocabState = JSON.parse(localStorage.getItem("feVocab") || "{}");

function $(sel, ctx) { return (ctx || document).querySelector(sel); }
function $$(sel, ctx) { return Array.from((ctx || document).querySelectorAll(sel)); }

function esc(s) {
  if (!s) return "";
  return String(s).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;");
}

function md(s) {
  if (!s) return "";
  return esc(s).replace(/\*\*\*(.+?)\*\*\*/g, "<strong><em>$1</em></strong>")
    .replace(/\*\*(.+?)\*\*/g, "<strong>$1</strong>")
    .replace(/\*(.+?)\*/g, "<em>$1</em>")
    .replace(/\n/g, "<br>");
}

function saveProgress() {
  try {
    localStorage.setItem("feCompleted", JSON.stringify(completedLessons));
    localStorage.setItem("feVocab", JSON.stringify(vocabState));
  } catch(e) {}
}

/* ---- Theme ---- */
function getTheme() {
  return localStorage.getItem("feTheme") || "system";
}
function setTheme(mode) {
  var html = document.documentElement;
  if (mode === "dark") { html.setAttribute("data-theme", "dark"); }
  else if (mode === "light") { html.setAttribute("data-theme", "light"); }
  else { html.removeAttribute("data-theme"); }
  localStorage.setItem("feTheme", mode);
  updateThemeIcon();
}
function toggleTheme() {
  var cur = getTheme();
  if (cur === "light") setTheme("dark");
  else if (cur === "dark") setTheme("system");
  else setTheme("light");
}
function updateThemeIcon() {
  var icon = $("#themeIcon");
  if (!icon) return;
  var cur = getTheme();
  if (cur === "dark") icon.textContent = "\u2600";
  else if (cur === "light") icon.textContent = "\u263E";
  else icon.textContent = "\u2600";
}

/* ---- Snackbar ---- */
function showSnackbar(msg, actionLabel, actionFn) {
  var sb = $("#snackbar");
  var msgEl = $("#snackbarMessage");
  var actEl = $("#snackbarAction");
  if (!sb || !msgEl) return;
  msgEl.textContent = msg;
  if (actionLabel && actionFn) {
    actEl.textContent = actionLabel;
    actEl.style.display = "";
    actEl.onclick = function() { actionFn(); hideSnackbar(); };
  } else {
    actEl.style.display = "none";
    actEl.onclick = null;
  }
  sb.setAttribute("aria-hidden", "false");
  if (window.snackbarTimeout) clearTimeout(window.snackbarTimeout);
  window.snackbarTimeout = setTimeout(hideSnackbar, 4000);
}
function hideSnackbar() {
  var sb = $("#snackbar");
  if (sb) sb.setAttribute("aria-hidden", "true");
}

/* ---- Drawer toggle (mobile) ---- */
function openDrawer() {
  var drawer = $("#sidebar");
  var scrim = $("#drawerScrim");
  if (drawer) drawer.classList.add("open");
  if (scrim) scrim.classList.add("open");
}
function closeDrawer() {
  var drawer = $("#sidebar");
  var scrim = $("#drawerScrim");
  if (drawer) drawer.classList.remove("open");
  if (scrim) scrim.classList.remove("open");
}

/* ---- Lesson completion ---- */
function toggleComplete(id) {
  var idx = completedLessons.indexOf(id);
  if (idx > -1) completedLessons.splice(idx, 1);
  else completedLessons.push(id);
  saveProgress();
  renderSidebar();
  updateLessonActions();
  var msg = completedLessons.includes(id) ? "Lesson marked complete" : "Lesson unmarked";
  showSnackbar(msg, "Undo", function() {
    toggleComplete(id);
  });
}

function updateLessonActions() {
  if (!currentLesson) return;
  var btn = document.querySelector("#lessonContent .btn-complete");
  if (btn) btn.textContent = completedLessons.includes(currentLesson.id) ? "Unmark Complete" : "Mark Complete";
}

function renderSidebar() {
  var list = $("#lessonList");
  list.innerHTML = LESSONS.map(function(l) {
    var active = currentLesson && currentLesson.id === l.id ? " active" : "";
    var done = completedLessons.includes(l.id) ? " completed" : "";
    return '<div class="lesson-item' + active + done + '" data-id="' + l.id + '">' +
      '<span class="lesson-number">' + l.id + '</span>' +
      '<span class="lesson-title">' + esc(l.title) + '</span>' +
      (completedLessons.includes(l.id) ? '<span class="lesson-check">&#10003;</span>' : "") +
      "</div>";
  }).join("");
  $("#completedCount").textContent = completedLessons.length;
  $("#totalCount").textContent = LESSONS.length;
}

function renderLesson(id) {
  var lesson = LESSONS.find(function(l) { return l.id === id; });
  if (!lesson) return;
  currentLesson = lesson;
  currentTab = "reading";
  $("#welcome").style.display = "none";

  var titleEl = $("#appBarTitle");
  if (titleEl) titleEl.textContent = "Lesson " + lesson.id + ": " + lesson.title;

  var main = $("#lessonContent");
  main.style.display = "block";

  var tabs = [
    {id:"reading", label:"Reading"},
    {id:"vocabulary", label:"Vocabulary"},
    {id:"grammar", label:"Grammar"},
    {id:"phrasal", label:"Phrasal Verbs"},
    {id:"real", label:"Real English"},
    {id:"review", label:"Exercises"},
    {id:"culture", label:"Culture"}
  ];

  var tabBtns = tabs.map(function(t) {
    var activeCls = t.id === currentTab ? " active" : "";
    return '<button class="tab-btn' + activeCls + '" onclick="FE.switchTab(\'' + t.id + '\')">' + t.label + "</button>";
  }).join("");

  main.innerHTML =
    '<div class="lesson-title-hero">Lesson ' + lesson.id + ': ' + esc(lesson.title) + "</div>" +
    '<div class="lesson-intro">' + esc(lesson.intro) + "</div>" +
    '<div class="lesson-tab-bar">' + tabBtns + "</div><div id='tabContent'></div>";

  renderSidebar();
  renderTab("reading");
}

function renderTab(tabId) {
  currentTab = tabId;
  if (!currentLesson) return;
  var tc = $("#tabContent");
  var l = currentLesson;
  var html = "";

  switch (tabId) {
    case "reading":
      html = '<div class="section"><div class="section-header"><h2>English at Work</h2></div>' +
        '<div class="reading-box"><div class="reading-context">Dialogue / Reading passage</div>' +
        '<div class="reading-lines">' + md(l.reading) + "</div></div></div>";
      break;

    case "vocabulary":
      html = '<div class="section"><div class="section-header"><h2>Vocabulary (' + l.vocabulary.length + ' words)</h2></div>' +
        '<div class="vocab-controls">' +
        '<button class="md-filled-tonal-button md-button-sm" onclick="FE.shuffleVocab()">Shuffle</button>' +
        '<button class="md-outlined-button md-button-sm" onclick="FE.resetVocab()">Reset Cards</button>' +
        "</div>" +
        '<div class="vocab-grid" id="vocabGrid">' +
        l.vocabulary.map(function(v, i) {
          return '<div class="vocab-card" data-vi="' + i + '" onclick="FE.flipVocab(this)" tabindex="0" onkeydown="if(event.key===\'Enter\'||event.key===\' \'){event.preventDefault();FE.flipVocab(this)}">' +
            '<div class="vocab-card-inner">' +
            '<div class="vocab-card-front"><div class="term">' + esc(v.term) + '</div><div class="hint">Tap to reveal</div></div>' +
            '<div class="vocab-card-back">' +
            '<div class="definition">' + esc(v.definition) + "</div>" +
            (v.example ? '<div class="example">"' + esc(v.example) + '"</div>' : "") +
            '<div class="vocab-difficulty">' +
            '<button class="diff-btn" data-d="easy" onclick="event.stopPropagation();FE.markVocab(' + i + ",'easy')" + '">Easy</button>' +
            '<button class="diff-btn" data-d="medium" onclick="event.stopPropagation();FE.markVocab(' + i + ",'medium')" + '">Medium</button>' +
            '<button class="diff-btn" data-d="hard" onclick="event.stopPropagation();FE.markVocab(' + i + ",'hard')" + '">Hard</button>' +
            "</div></div></div></div>";
        }).join("") +
        "</div></div>";
      break;

    case "grammar":
      html = '<div class="section"><div class="section-header"><h2>English Under the Hood</h2></div>' +
        l.grammar.map(function(g, gi) {
          var body = '<div class="explanation">' + md(g.explanation) + "</div>";
          if (g.practice && g.practice.items && g.practice.items.length > 0) {
            body += '<div class="exercise"><h4>' + esc(g.practice.title) + "</h4>" +
              g.practice.items.map(function(item, ii) {
                return '<div class="exercise-item"><div class="sentence">' + md(item.sentence) +
                  '</div><input type="text" class="quiz-input" data-gi="' + gi + '" data-ii="' + ii +
                  '" placeholder="Type answer..." onkeydown="if(event.key===\'Enter\')FE.checkGP(this)">' +
                  '<div class="quiz-feedback"></div></div>';
              }).join("") +
              '<div class="quiz-buttons">' +
              '<button class="md-filled-button md-button-sm" onclick="FE.checkAllGP(' + gi + ')">Check All</button>' +
              '<button class="md-outlined-button md-button-sm" onclick="FE.revealAllGP(' + gi + ')">Reveal Answers</button>' +
              "</div></div>";
          }
          return '<div class="grammar-accordion open" onclick="FE.toggleGram(this)" role="button" tabindex="0" onkeydown="if(event.key===\'Enter\'||event.key===\' \'){event.preventDefault();FE.toggleGram(this)}">' +
            '<div class="grammar-header"><span>' + esc(g.topic) + '</span><span class="arrow">&#9654;</span></div>' +
            '<div class="grammar-body"><div class="grammar-body-inner">' + body + "</div></div></div>";
        }).join("") +
        "</div>";
      break;

    case "phrasal":
      html = '<div class="section"><div class="section-header"><h2>Phrasal Verbs (' + l.phrasalVerbs.length + ' verbs)</h2></div>' +
        '<div class="md-search-bar" style="margin-bottom:var(--md-sys-spacing-lg);max-width:400px">' +
        '<span class="search-icon"></span>' +
        '<input type="text" placeholder="Search phrasal verbs..." oninput="FE.filterPV(this.value)" aria-label="Search phrasal verbs">' +
        "</div>" +
        '<div class="pv-grid" id="pvGrid">' +
        l.phrasalVerbs.map(function(pv) {
          return '<div class="pv-card" data-pvt="' + esc(pv.verb.toLowerCase()) + '">' +
            '<div class="pv-verb">' + esc(pv.verb) + "</div>" +
            pv.meanings.map(function(m) {
              return '<div class="pv-meaning">' + esc(m.text) + "</div>";
            }).join("") +
            "</div>";
        }).join("") +
        "</div></div>";
      break;

    case "real":
      html = '<div class="section"><div class="section-header"><h2>Real English</h2></div>' +
        '<div class="real-english"><div class="re-content">' + md(l.realEnglish) + "</div></div></div>";
      break;

    case "review":
      var doneLabel = completedLessons.includes(l.id) ? "Unmark Complete" : "Mark Complete";
      html = '<div class="section"><div class="section-header"><h2>Bring It All Together</h2></div>' +
        l.reviewExercises.map(function(re, ri) {
          return '<div class="exercise"><h4>' + esc(re.title) + "</h4>" +
            re.items.map(function(item, ii) {
              return '<div class="exercise-item"><div class="sentence">' + md(item.question) +
                '</div><input type="text" class="quiz-input" data-ri="' + ri + '" data-ii="' + ii +
                '" placeholder="Type answer..." onkeydown="if(event.key===\'Enter\')FE.checkRV(this)">' +
                '<div class="quiz-feedback"></div></div>';
            }).join("") +
            '<div class="quiz-buttons">' +
            '<button class="md-filled-button md-button-sm" onclick="FE.checkAllRV(' + ri + ')">Check All</button>' +
            '<button class="md-outlined-button md-button-sm" onclick="FE.revealAllRV(' + ri + ')">Reveal All</button>' +
            "</div></div>";
        }).join("") +
        answerKeyHTML(l) +
        '<div style="margin-top:var(--md-sys-spacing-xl);text-align:center">' +
        '<button class="md-filled-tonal-button btn-complete" onclick="FE.toggleComplete(' + l.id + ')">' + doneLabel + "</button>" +
        "</div>" +
        "</div>";
      break;

    case "culture":
      html = '<div class="section"><div class="section-header"><h2>Why Do They Do That?</h2></div>' +
        '<div class="culture-note"><p>' + md(l.cultureNote) + "</p></div></div>";
      break;
  }

  tc.innerHTML = html;

  if (tabId === "vocabulary") {
    setTimeout(function() {
      $$(".vocab-card").forEach(function(el) {
        var idx = parseInt(el.dataset.vi);
        var key = currentLesson.id + "-" + idx;
        if (vocabState[key]) {
          el.classList.add("flipped");
          var btn = el.querySelector('.diff-btn[data-d="' + vocabState[key] + '"]');
          if (btn) btn.classList.add("active-" + vocabState[key]);
        }
      });
    }, 50);
  }
}

function answerKeyHTML(l) {
  var keys = Object.keys(l.answerKey);
  if (!keys.length) return '<p style="color:var(--md-sys-color-on-surface-variant);font-size:14px;margin-top:1rem">Answer key not available for this lesson.</p>';
  var html = '<div class="answer-key">' +
    '<div class="answer-key-header" onclick="FE.toggleAnswerKey(this)" role="button" tabindex="0" onkeydown="if(event.key===\'Enter\'||event.key===\' \'){event.preventDefault();FE.toggleAnswerKey(this)}">' +
    '<span>View Answer Key</span><span class="ak-arrow">&#9654;</span></div>' +
    '<div class="answer-key-body"><div class="answer-key-body-inner">';
  keys.forEach(function(k) {
    var items = l.answerKey[k];
    var formatted = esc(items).replace(/\\n/g, "<br>");
    html += '<div class="ak-section"><div class="ak-title">' + esc(k) + "</div>" +
      '<div class="ak-items">' + formatted + "</div></div>";
  });
  html += "</div></div></div>";
  return html;
}

function toggleAnswerKey(el) {
  el.parentElement.classList.toggle("open");
}

function flipVocab(el) {
  el.classList.toggle("flipped");
}

function shuffleVocab() {
  var grid = $("#vocabGrid");
  if (!grid) return;
  var cards = $$(".vocab-card", grid);
  for (var i = cards.length - 1; i > 0; i--) {
    var j = Math.floor(Math.random() * (i + 1));
    grid.insertBefore(cards[j], cards[i]);
  }
}

function resetVocab() {
  $$(".vocab-card").forEach(function(c) {
    c.classList.remove("flipped");
    c.querySelectorAll(".diff-btn").forEach(function(b) { b.className = "diff-btn"; });
  });
  Object.keys(vocabState).forEach(function(k) {
    if (k.indexOf(currentLesson.id + "-") === 0) delete vocabState[k];
  });
  saveProgress();
}

function markVocab(idx, diff) {
  var key = currentLesson.id + "-" + idx;
  var card = document.querySelector('.vocab-card[data-vi="' + idx + '"]');
  if (!card) return;
  card.querySelectorAll(".diff-btn").forEach(function(b) {
    b.className = "diff-btn";
    if (b.dataset.d === diff) b.classList.add("active-" + diff);
  });
  if (vocabState[key] === diff) delete vocabState[key];
  else vocabState[key] = diff;
  saveProgress();
}

function toggleGram(el) {
  el.classList.toggle("open");
}

function switchTab(tab) {
  currentTab = tab;
  if (currentLesson) {
    var labelToId = {"reading":"Reading","vocabulary":"Vocabulary","grammar":"Grammar","phrasal":"Phrasal Verbs","real":"Real English","review":"Exercises","culture":"Culture"};
    var activeLabel = labelToId[tab] || tab;
    $$(".tab-btn").forEach(function(b) {
      b.classList.toggle("active", b.textContent === activeLabel);
    });
    renderTab(tab);
  }
}

function openLesson(id) {
  var l = LESSONS.find(function(x) { return x.id === id; });
  if (l) {
    closeDrawer();
    renderLesson(id);
  }
}

// Answer lookup - matches by exercise title similarity
function findAns(lessonId, type, gi, itemIdx) {
  var l = LESSONS.find(function(x) { return x.id === lessonId; });
  if (!l) return "";
  var keys = Object.keys(l.answerKey);

  if (type === "grammar") {
    var grammarTopic = l.grammar[gi];
    if (!grammarTopic || !grammarTopic.practice) return "";
    var targetTitle = grammarTopic.practice.title.toLowerCase().replace(/[^a-z0-9 ]/g, "").trim();
    for (var ki = 0; ki < keys.length; ki++) {
      var keyLower = keys[ki].toLowerCase().replace(/[^a-z0-9 ]/g, "").trim();
      var targetWords = targetTitle.split(/\s+/);
      var matchCount = 0;
      targetWords.forEach(function(w) {
        if (w.length > 2 && keyLower.indexOf(w) > -1) matchCount++;
      });
      if (matchCount >= 2 || targetTitle.indexOf(keyLower) > -1 || keyLower.indexOf(targetTitle) > -1) {
        return parseAnswerList(l.answerKey[keys[ki]], itemIdx);
      }
    }
    var practiceKeys = keys.filter(function(k) { return k.toLowerCase().indexOf("practice") > -1; }).sort();
    if (practiceKeys[gi]) return parseAnswerList(l.answerKey[practiceKeys[gi]], itemIdx);
  }

  if (type === "review") {
    var targetNum = gi + 1;
    for (var ki2 = 0; ki2 < keys.length; ki2++) {
      var kl = keys[ki2].toLowerCase();
      var numMatch = kl.match(/review\s*(?:exercise)?\s*(\d+)/);
      if (numMatch && parseInt(numMatch[1]) === targetNum) {
        return parseAnswerList(l.answerKey[keys[ki2]], itemIdx);
      }
    }
    var reviewKeys = keys.filter(function(k) { return k.toLowerCase().indexOf("review") > -1; }).sort();
    if (reviewKeys[gi]) return parseAnswerList(l.answerKey[reviewKeys[gi]], itemIdx);
  }

  return "";
}

function parseAnswerList(text, idx) {
  if (!text) return "";
  var lines = text.split("\n").filter(function(x) { return x.trim(); });
  if (lines.length === 0) return "";
  for (var i = 0; i < lines.length; i++) {
    var m = lines[i].match(/^(\d+)[\.)]\s*(.+)/);
    if (m && parseInt(m[1]) === idx + 1) return m[2].trim();
  }
  var joined = lines.join(" ");
  var parts = joined.split(/,\s+/);
  var found = 0;
  for (var pi = 0; pi < parts.length; pi++) {
    var pm = parts[pi].match(/^(\d+)[\.)]\s*(.+)/);
    if (pm) {
      found++;
      if (found === idx + 1) return pm[2].trim();
    }
  }
  var items = joined.split(/\d+[\.)]\s+/).filter(Boolean);
  if (items.length >= idx + 1) {
    return items[idx].replace(/[.,]\s*$/, "").trim();
  }
  return lines[0].trim();
}

function checkGP(el) {
  var gi = parseInt(el.dataset.gi);
  var ii = parseInt(el.dataset.ii);
  var fb = el.nextElementSibling;
  var answer = findAns(currentLesson.id, "grammar", gi, ii);
  if (!answer) {
    fb.textContent = "Answer not available.";
    fb.className = "quiz-feedback revealed";
    el.className = "quiz-input revealed";
    return;
  }
  var userAns = el.value.trim().toLowerCase().replace(/\s+/g, " ");
  var correct = String(answer).toLowerCase().replace(/\s+/g, " ").replace(/\/.*$/, "").trim();
  if (userAns === correct || (correct.indexOf(userAns) > -1 && userAns.length > 2)) {
    el.className = "quiz-input correct";
    fb.textContent = "Correct!";
    fb.className = "quiz-feedback correct";
  } else {
    el.className = "quiz-input wrong";
    fb.textContent = "Incorrect. Answer: " + answer;
    fb.className = "quiz-feedback wrong";
  }
}

function checkRV(el) {
  var ri = parseInt(el.dataset.ri);
  var ii = parseInt(el.dataset.ii);
  var fb = el.nextElementSibling;
  var answer = findAns(currentLesson.id, "review", ri, ii);
  if (!answer) {
    fb.textContent = "Answer not available.";
    fb.className = "quiz-feedback revealed";
    el.className = "quiz-input revealed";
    return;
  }
  var userAns = el.value.trim().toLowerCase().replace(/\s+/g, " ");
  var correct = String(answer).toLowerCase().replace(/\s+/g, " ").replace(/\/.*$/, "").trim();
  if (userAns === correct || (correct.indexOf(userAns) > -1 && userAns.length > 2)) {
    el.className = "quiz-input correct";
    fb.textContent = "Correct!";
    fb.className = "quiz-feedback correct";
  } else {
    el.className = "quiz-input wrong";
    fb.textContent = "Incorrect. Answer: " + answer;
    fb.className = "quiz-feedback wrong";
  }
}

function checkAllGP(gi) {
  $$('.quiz-input[data-gi="' + gi + '"]').forEach(function(el) { checkGP(el); });
}

function revealAllGP(gi) {
  $$('.quiz-input[data-gi="' + gi + '"]').forEach(function(el) {
    var fb = el.nextElementSibling;
    var ii = parseInt(el.dataset.ii);
    var answer = findAns(currentLesson.id, "grammar", gi, ii);
    if (answer) {
      el.value = answer;
      el.className = "quiz-input revealed";
      fb.textContent = "Answer: " + answer;
      fb.className = "quiz-feedback revealed";
    }
  });
}

function checkAllRV(ri) {
  $$('.quiz-input[data-ri="' + ri + '"]').forEach(function(el) { checkRV(el); });
}

function revealAllRV(ri) {
  $$('.quiz-input[data-ri="' + ri + '"]').forEach(function(el) {
    var fb = el.nextElementSibling;
    var ii = parseInt(el.dataset.ii);
    var answer = findAns(currentLesson.id, "review", ri, ii);
    if (answer) {
      el.value = answer;
      el.className = "quiz-input revealed";
      fb.textContent = "Answer: " + answer;
      fb.className = "quiz-feedback revealed";
    }
  });
}

function filterPV(val) {
  var q = val.toLowerCase();
  $$(".pv-card").forEach(function(c) {
    c.style.display = c.dataset.pvt.indexOf(q) > -1 ? "" : "none";
  });
}

function searchLessons(q) {
  var term = q.toLowerCase();
  $$(".lesson-item").forEach(function(el) {
    var title = el.querySelector(".lesson-title").textContent.toLowerCase();
    var id = parseInt(el.dataset.id);
    var lesson = LESSONS.find(function(l) { return l.id === id; });
    var match = title.indexOf(term) > -1 || (lesson && lesson.intro.toLowerCase().indexOf(term) > -1);
    el.style.display = match ? "" : "none";
  });
}

function startReview() {
  var overlay = $("#reviewOverlay");
  if (!overlay) return;
  overlay.style.display = "flex";

  var allItems = [];
  LESSONS.forEach(function(l) {
    l.vocabulary.forEach(function(v) {
      allItems.push({ lesson: l.id, type: "Vocabulary", q: v.term, a: v.definition });
    });
    l.phrasalVerbs.forEach(function(pv) {
      allItems.push({ lesson: l.id, type: "Phrasal Verb", q: pv.verb, a: pv.meanings.map(function(m) { return m.text; }).join("; ") });
    });
  });

  for (var i = allItems.length - 1; i > 0; i--) {
    var j = Math.floor(Math.random() * (i + 1));
    var tmp = allItems[i]; allItems[i] = allItems[j]; allItems[j] = tmp;
  }

  var content = $("#reviewContent");
  var idx = 0;
  function renderItem() {
    if (idx >= allItems.length) {
      content.innerHTML = '<div style="text-align:center;padding:2rem"><div class="md-title-medium" style="color:var(--md-sys-color-success);margin-bottom:1rem">Review complete!</div>' +
        '<button class="md-filled-button" onclick="FE.closeReview()">Close</button></div>';
      return;
    }
    var item = allItems[idx];
    content.innerHTML =
      '<div class="review-counter">Question ' + (idx + 1) + ' of ' + allItems.length + "</div>" +
      '<div class="review-item">' +
      '<div class="review-badge">Lesson ' + item.lesson + " &middot; " + item.type + "</div>" +
      '<div class="review-question">' + esc(item.q) + "</div>" +
      '<button class="md-outlined-button md-button-sm" onclick="var a=this.nextElementSibling;a.classList.toggle(\'show\');this.textContent=a.classList.contains(\'show\')?\'Hide Answer\':\'Show Answer\'">Show Answer</button>' +
      '<div class="review-answer">' + esc(item.a) + "</div>" +
      '<div class="review-controls">' +
      '<button class="md-filled-button md-button-sm" id="reviewNext">Next</button>' +
      '<button class="md-text-button md-button-sm" onclick="FE.closeReview()">Close</button>' +
      "</div></div>";
    $("#reviewNext").onclick = function() { idx++; renderItem(); };
  }
  renderItem();
}

function closeReview() {
  var overlay = $("#reviewOverlay");
  if (overlay) overlay.style.display = "none";
}

function init() {
  setTheme(getTheme());
  renderSidebar();

  var menuBtn = $("#menuBtn");
  if (menuBtn) menuBtn.addEventListener("click", openDrawer);

  document.addEventListener("click", function(e) {
    var item = e.target.closest(".lesson-item");
    if (item) {
      var id = parseInt(item.dataset.id);
      openLesson(id);
    }
  });

  var searchInput = $("#searchInput");
  if (searchInput) {
    searchInput.addEventListener("input", function() {
      searchLessons(this.value);
    });
  }

  var reviewBtn = $("#reviewModeBtn");
  if (reviewBtn) {
    reviewBtn.addEventListener("click", startReview);
  }

  var themeBtn = $("#themeToggle");
  if (themeBtn) {
    themeBtn.addEventListener("click", toggleTheme);
  }

  document.addEventListener("keydown", function(e) {
    if (e.key === "Escape") {
      closeReview();
      closeDrawer();
    }
  });
}

window.FE = {
  openLesson: openLesson,
  switchTab: switchTab,
  flipVocab: flipVocab,
  shuffleVocab: shuffleVocab,
  resetVocab: resetVocab,
  markVocab: markVocab,
  toggleGram: toggleGram,
  checkGP: checkGP,
  checkRV: checkRV,
  checkAllGP: checkAllGP,
  revealAllGP: revealAllGP,
  checkAllRV: checkAllRV,
  revealAllRV: revealAllRV,
  filterPV: filterPV,
  toggleComplete: toggleComplete,
  startReview: startReview,
  closeReview: closeReview,
  toggleAnswerKey: toggleAnswerKey,
  toggleTheme: toggleTheme,
  openDrawer: openDrawer,
  closeDrawer: closeDrawer
};

if (document.readyState === "loading") {
  document.addEventListener("DOMContentLoaded", init);
} else {
  init();
}
})();
